body.script:
document.addEventListener("DOMContentLoaded", () => {
  const logoObj = document.getElementById("brakexLogo");
  logoObj.addEventListener("load", () => {
    const svgDoc = logoObj.contentDocument;
    const disc = svgDoc.getElementById("discRot");
    const icon = svgDoc.getElementById("icon");
    const text = svgDoc.getElementById("brandMain");

    // Rotación continua del disco
    gsap.to(disc, {
      rotation: -360,
      transformOrigin: "center center",
      repeat: -1,
      ease: "linear",
      duration: 3
    });

    // Efecto flotante del icono
    gsap.to(icon, {
      y: -6,
      scale: 1.02,
      duration: 2.4,
      ease: "sine.inOut",
      yoyo: true,
      repeat: -1
    });

    // Aparición del texto con brillo
    gsap.fromTo(text, {opacity: 0, x: -20}, {opacity: 1, x: 0, duration: 1.4, ease: "power2.out"});

    // Hover: acelera el giro
    logoObj.addEventListener("mouseenter", () => {
      gsap.to(disc, {duration: 0.3, rotation: "+=60", ease: "power2.out"});
    });
  });
});
